// ── Slow room layout (fixed) ──────────────────────────────────────────────────
// 10 mats in 2 rows of 5, numbered column-first (odd → row 1, even → row 2)
export const SLOW_MATS = [
  { id: 'R1-S1', num: '01', row: 1 },
  { id: 'R1-S2', num: '03', row: 1 },
  // position 3 of row 1 is the coach — no mat 05
  { id: 'R1-S4', num: '07', row: 1 },
  { id: 'R1-S5', num: '09', row: 1 },
  { id: 'R2-S1', num: '02', row: 2 },
  { id: 'R2-S2', num: '04', row: 2 },
  { id: 'R2-S3', num: '06', row: 2 },
  { id: 'R2-S4', num: '08', row: 2 },
  { id: 'R2-S5', num: '10', row: 2 },
]
function slowMatNum(id) {
  return SLOW_MATS.find(m => m.id === id)?.num ?? '??'
}
function slowIdFromAsiento(asiento) {
  const m = asiento?.match(/^Mat (\d+)$/)
  if (m) return SLOW_MATS.find(mat => mat.num === m[1].padStart(2, '0'))?.id ?? null
  return seatIdFromLabel(asiento)
}

